1	// Glues CsrTrigger and StateDrain. The simulator's run-loop calls on_retire
2	// once per committed PC; the controller decides via the trigger map whether
3	// to drain state and returns the populated hybrid_state_v1 if so. The
4	// caller (simulator.hpp) is responsible for writing the file and exiting
5	// with EXIT_HANDOFF_TO_QEMU.
6	
7	#pragma once
8	
9	#include "hybrid/csr_trigger.hpp"
10	#include "hybrid/insn_match.h"
11	#include "hybrid/resume_driver.hpp"
12	#include "hybrid/state_abi.h"
13	#include "hybrid/state_drain.hpp"
14	
15	#include <cstdint>
16	#include <optional>
17	#include <utility>
18	
19	namespace hybrid
20	{
21	
22	class HandoffController
23	{
24	public:
25	  HandoffController(CsrTrigger trigger, DmiBus& bus)
26	      : trigger_{std::move(trigger)}, drain_{bus}
27	  {}
28	
29	  // Snapshot of the QEMU 1 input state. When set, drain merges FP/CSR/V
30	  // fields from the snapshot into the freshly drained GPRs+PC, avoiding
31	  // a per-field DM Abstract Command on every handoff.
32	  void set_passthrough_input(hybrid_state_v1 input)
33	  {
34	    passthrough_ = input;
35	  }
36	
37	  template<typename GprProbe>
38	  auto on_retire(uint64_t pc, GprProbe&& read_gpr)
39	    -> std::optional<hybrid_state_v1>
40	  {
41	    const auto hit = trigger_.lookup(pc);
42	    if (!hit) return std::nullopt;
43	
44	    bool fire = false;
45	    switch (hit->kind) {
46	    case HYBRID_HANDOFF_EXIT:
47	      fire = true;
48	      break;
49	    case HYBRID_HANDOFF_RUNTIME: {
50	      const auto rs1 = decode_csrrw_rs1(hit->insn);
51	      fire = (read_gpr(rs1) == 1u);
52	      break;
53	    }
54	    case HYBRID_HANDOFF_ENTER:  // entry is QEMU's job; vsim ignores it
55	    case HYBRID_HANDOFF_NONE:
56	      break;
57	    }
58	    if (!fire) return std::nullopt;
59	    if (passthrough_) return drain_.drain_with_passthrough(*passthrough_);
60	    return drain_.drain();
61	  }
62	
63	private:
64	  CsrTrigger trigger_;
65	  StateDrain drain_;
66	  std::optional<hybrid_state_v1> passthrough_;
67	};
68	
69	}  // namespace hybrid
